1	package workflow
2	
3	import (
4		"encoding/json"
5		"fmt"
6		"strconv"
7	
8		"github.com/github/gh-aw/pkg/logger"
9		"github.com/github/gh-aw/pkg/stringutil"
10	)
11	
12	var engineLog = logger.New("workflow:engine")
13	
14	// EngineConfig represents the parsed engine configuration
15	type EngineConfig struct {
16		ID               string
17		Version          string
18		Model            string
19		MaxTurns         string
20		MaxContinuations int    // Maximum number of continuations for autopilot mode (copilot engine only; > 1 enables --autopilot)
21		Concurrency      string // Agent job-level concurrency configuration (YAML format)
22		UserAgent        string
23		Command          string // Custom executable path (when set, skip installation steps)
24		Env              map[string]string
25		Config           string
26		Args             []string
27		Agent            string // Agent identifier for copilot --agent flag (copilot engine only)
28		APITarget        string // Custom API endpoint hostname (e.g., "api.acme.ghe.com" or "api.enterprise.githubcopilot.com")
29	
30		// Inline definition fields (populated when engine.runtime is specified in frontmatter)
31		IsInlineDefinition bool   // true when the engine is defined inline via engine.runtime + optional engine.provider
32		InlineProviderID   string // engine.provider.id  (e.g. "openai", "anthropic")
33		// Deprecated: Use InlineProviderAuth instead. Kept for backwards compatibility when only
34		// engine.provider.auth.secret is specified without a strategy.
35		InlineProviderSecret string // engine.provider.auth.secret  (backwards compat: simple API key secret name)
36	
37		// Extended inline auth fields (engine.provider.auth.* beyond the simple secret)
38		InlineProviderAuth *AuthDefinition // full auth definition parsed from engine.provider.auth
39	
40		// Extended inline request shaping fields (engine.provider.request.*)
41		InlineProviderRequest *RequestShape // request shaping parsed from engine.provider.request
42	}
43	
44	// NetworkPermissions represents network access permissions for workflow execution
45	// Controls which domains the workflow can access during execution.
46	//
47	// The Allowed field specifies which domains/ecosystems are permitted:
48	//   - nil/not set: Use default ecosystem domains (backwards compatibility)
49	//   - []: Empty list means deny all network access
50	//   - ["defaults"]: Use default ecosystem domains
51	//   - ["defaults", "github", "python"]: Expand and merge multiple ecosystems
52	//   - ["example.com"]: Allow specific domain only
53	//
54	// Examples:
55	//
56	//  1. String format - use default domains only:
57	//     network: defaults
58	//     Result: NetworkPermissions{Allowed: ["defaults"], ExplicitlyDefined: true}
59	//
60	//  2. Object format - specify allowed ecosystems/domains:
61	//     network:
62	//     allowed:
63	//     - defaults      # Expands to default ecosystem domains (certs, JSON schema, Ubuntu, etc.)
64	//     - github        # Expands to GitHub ecosystem domains (*.githubusercontent.com, etc.)
65	//     - example.com   # Literal domain
66	//     Result: NetworkPermissions{Allowed: ["defaults", "github", "example.com"], ExplicitlyDefined: true}
67	//
68	//  3. Empty object - deny all network access:
69	//     network: {}
70	//     Result: NetworkPermissions{Allowed: [], ExplicitlyDefined: true}
71	//
72	// Ecosystem identifiers in the Allowed list are expanded to their corresponding domain lists.
73	// See GetAllowedDomains() for the list of supported ecosystem identifiers.
74	type NetworkPermissions struct {
75		Allowed           []string        `yaml:"allowed,omitempty"`  // List of allowed domains or ecosystem identifiers (e.g., "defaults", "github", "python")
76		Blocked           []string        `yaml:"blocked,omitempty"`  // List of blocked domains (takes precedence over allowed)
77		Firewall          *FirewallConfig `yaml:"firewall,omitempty"` // AWF firewall configuration (see firewall.go)
78		ExplicitlyDefined bool            `yaml:"-"`                  // Internal flag: true if network field was explicitly set in frontmatter
79	}
80	
81	// EngineNetworkConfig combines engine configuration with top-level network permissions
82	type EngineNetworkConfig struct {
83		Engine  *EngineConfig
84		Network *NetworkPermissions
85	}
86	
87	// ExtractEngineConfig extracts engine configuration from frontmatter, supporting both string and object formats
88	func (c *Compiler) ExtractEngineConfig(frontmatter map[string]any) (string, *EngineConfig) {
89		if engine, exists := frontmatter["engine"]; exists {
90			engineLog.Print("Extracting engine configuration from frontmatter")
91	
92			// Handle string format (backwards compatibility)
93			if engineStr, ok := engine.(string); ok {
94				engineLog.Printf("Found engine in string format: %s", engineStr)
95				return engineStr, &EngineConfig{ID: engineStr}
96			}
97	
98			// Handle object format
99			if engineObj, ok := engine.(map[string]any); ok {
100				engineLog.Print("Found engine in object format, parsing configuration")
101				config := &EngineConfig{}
102	
103				// Detect inline definition: engine.runtime sub-object present instead of engine.id
104				if runtime, hasRuntime := engineObj["runtime"]; hasRuntime {
105					engineLog.Print("Found inline engine definition (engine.runtime sub-object)")
106					config.IsInlineDefinition = true
107	
108					if runtimeObj, ok := runtime.(map[string]any); ok {
109						if id, ok := runtimeObj["id"].(string); ok {
110							config.ID = id
111							engineLog.Printf("Inline engine runtime.id: %s", config.ID)
112						}
113						if version, hasVersion := runtimeObj["version"]; hasVersion {
114							config.Version = stringutil.ParseVersionValue(version)
115						}
116					}
117	
118					// Extract optional provider sub-object
119					if provider, hasProvider := engineObj["provider"]; hasProvider {
120						if providerObj, ok := provider.(map[string]any); ok {
121							if id, ok := providerObj["id"].(string); ok {
122								config.InlineProviderID = id
123							}
124							if model, ok := providerObj["model"].(string); ok {
125								config.Model = model
126							}
127							if auth, hasAuth := providerObj["auth"]; hasAuth {
128								if authObj, ok := auth.(map[string]any); ok {
129									authDef := parseAuthDefinition(authObj)
130									// Only store an AuthDefinition when the user actually provided
131									// at least one recognised field.  An empty map (e.g. `auth: {}`)
132									// must not be treated as an explicit auth override.
133									if authDef.Strategy != "" || authDef.Secret != "" ||
134										authDef.TokenURL != "" || authDef.ClientIDRef != "" ||
135										authDef.ClientSecretRef != "" || authDef.HeaderName != "" ||
136										authDef.TokenField != "" {
137										config.InlineProviderAuth = authDef
138										// Backwards compat: expose the simple secret field directly.
139										config.InlineProviderSecret = authDef.Secret
140									}
141								}
142							}
143							if request, hasRequest := providerObj["request"]; hasRequest {
144								if requestObj, ok := request.(map[string]any); ok {
145									config.InlineProviderRequest = parseRequestShape(requestObj)
146								}
147							}
148						}
149					}
150	
151					engineLog.Printf("Extracted inline engine definition: runtimeID=%s, providerID=%s", config.ID, config.InlineProviderID)
152					return config.ID, config
153				}
154	
155				// Extract required 'id' field
156				if id, hasID := engineObj["id"]; hasID {
157					if idStr, ok := id.(string); ok {
158						config.ID = idStr
159					}
160				}
161	
162				// Extract optional 'version' field
163				if version, hasVersion := engineObj["version"]; hasVersion {
164					config.Version = stringutil.ParseVersionValue(version)
165				}
166	
167				// Extract optional 'model' field
168				if model, hasModel := engineObj["model"]; hasModel {
169					if modelStr, ok := model.(string); ok {
170						config.Model = modelStr
171					}
172				}
173	
174				// Extract optional 'max-turns' field
175				if maxTurns, hasMaxTurns := engineObj["max-turns"]; hasMaxTurns {
176					if maxTurnsInt, ok := maxTurns.(int); ok {
177						config.MaxTurns = strconv.Itoa(maxTurnsInt)
178					} else if maxTurnsUint64, ok := maxTurns.(uint64); ok {
179						config.MaxTurns = strconv.FormatUint(maxTurnsUint64, 10)
180					} else if maxTurnsStr, ok := maxTurns.(string); ok {
181						config.MaxTurns = maxTurnsStr
182					}
183				}
184	
185				// Extract optional 'max-continuations' field
186				if maxCont, hasMaxCont := engineObj["max-continuations"]; hasMaxCont {
187					if maxContInt, ok := maxCont.(int); ok {
188						config.MaxContinuations = maxContInt
189					} else if maxContUint64, ok := maxCont.(uint64); ok {
190						config.MaxContinuations = int(maxContUint64)
191					} else if maxContStr, ok := maxCont.(string); ok {
192						if parsed, err := strconv.Atoi(maxContStr); err == nil {
193							config.MaxContinuations = parsed
194						}
195					}
196				}
197	
198				// Extract optional 'concurrency' field (string or object format)
199				if concurrency, hasConcurrency := engineObj["concurrency"]; hasConcurrency {
200					if concurrencyStr, ok := concurrency.(string); ok {
201						// Simple string format (group name)
202						config.Concurrency = fmt.Sprintf("concurrency:\n  group: \"%s\"", concurrencyStr)
203					} else if concurrencyObj, ok := concurrency.(map[string]any); ok {
204						// Object format with group and optional cancel-in-progress
205						var parts []string
206						if group, hasGroup := concurrencyObj["group"]; hasGroup {
207							if groupStr, ok := group.(string); ok {
208								parts = append(parts, fmt.Sprintf("concurrency:\n  group: \"%s\"", groupStr))
209							}
210						}
211						if cancel, hasCancel := concurrencyObj["cancel-in-progress"]; hasCancel {
212							if cancelBool, ok := cancel.(bool); ok && cancelBool {
213								if len(parts) > 0 {
214									parts[0] += "\n  cancel-in-progress: true"
215								}
216							}
217						}
218						if len(parts) > 0 {
219							config.Concurrency = parts[0]
220						}
221					}
222				}
223	
224				// Extract optional 'user-agent' field
225				if userAgent, hasUserAgent := engineObj["user-agent"]; hasUserAgent {
226					if userAgentStr, ok := userAgent.(string); ok {
227						config.UserAgent = userAgentStr
228					}
229				}
230	
231				// Extract optional 'command' field
232				if command, hasCommand := engineObj["command"]; hasCommand {
233					if commandStr, ok := command.(string); ok {
234						config.Command = commandStr
235					}
236				}
237	
238				// Extract optional 'env' field (object/map of strings)
239				if env, hasEnv := engineObj["env"]; hasEnv {
240					if envMap, ok := env.(map[string]any); ok {
241						config.Env = make(map[string]string)
242						for key, value := range envMap {
243							if valueStr, ok := value.(string); ok {
244								config.Env[key] = valueStr
245							}
246						}
247					}
248				}
249	
250				// Extract optional 'config' field (additional TOML configuration)
251				if config_field, hasConfig := engineObj["config"]; hasConfig {
252					if configStr, ok := config_field.(string); ok {
253						config.Config = configStr
254					}
255				}
256	
257				// Extract optional 'args' field (array of strings)
258				if args, hasArgs := engineObj["args"]; hasArgs {
259					if argsArray, ok := args.([]any); ok {
260						config.Args = make([]string, 0, len(argsArray))
261						for _, arg := range argsArray {
262							if argStr, ok := arg.(string); ok {
263								config.Args = append(config.Args, argStr)
264							}
265						}
266					} else if argsStrArray, ok := args.([]string); ok {
267						config.Args = argsStrArray
268					}
269				}
270	
271				// Extract optional 'agent' field (string - copilot engine only)
272				if agent, hasAgent := engineObj["agent"]; hasAgent {
273					if agentStr, ok := agent.(string); ok {
274						config.Agent = agentStr
275						engineLog.Printf("Extracted agent identifier: %s", agentStr)
276					}
277				}
278	
279				// Extract optional 'api-target' field (custom API endpoint for any engine)
280				if apiTarget, hasAPITarget := engineObj["api-target"]; hasAPITarget {
281					if apiTargetStr, ok := apiTarget.(string); ok && apiTargetStr != "" {
282						config.APITarget = apiTargetStr
283						engineLog.Printf("Extracted api-target: %s", apiTargetStr)
284					}
285				}
286	
287				// Return the ID as the engineSetting for backwards compatibility
288				engineLog.Printf("Extracted engine configuration: ID=%s", config.ID)
289				return config.ID, config
290			}
291		}
292	
293		// No engine specified
294		engineLog.Print("No engine configuration found in frontmatter")
295		return "", nil
296	}
297	
298	// getAgenticEngine returns the agentic engine for the given engine setting
299	func (c *Compiler) getAgenticEngine(engineSetting string) (CodingAgentEngine, error) {
300		if engineSetting == "" {
301			defaultEngine := c.engineRegistry.GetDefaultEngine()
302			engineLog.Printf("Using default engine: %s", defaultEngine.GetID())
303			return defaultEngine, nil
304		}
305	
306		engineLog.Printf("Getting agentic engine for setting: %s", engineSetting)
307	
308		// First try exact match
309		if c.engineRegistry.IsValidEngine(engineSetting) {
310			engine, err := c.engineRegistry.GetEngine(engineSetting)
311			if err == nil {
312				engineLog.Printf("Found engine by exact match: %s", engine.GetID())
313			}
314			return engine, err
315		}
316	
317		// Try prefix match for backward compatibility
318		engine, err := c.engineRegistry.GetEngineByPrefix(engineSetting)
319		if err == nil {
320			engineLog.Printf("Found engine by prefix match: %s", engine.GetID())
321		} else {
322			engineLog.Printf("Failed to find engine for setting %s: %v", engineSetting, err)
323		}
324		return engine, err
325	}
326	
327	// extractEngineConfigFromJSON parses engine configuration from JSON string (from included files)
328	func (c *Compiler) extractEngineConfigFromJSON(engineJSON string) (*EngineConfig, error) {
329		if engineJSON == "" {
330			return nil, nil
331		}
332	
333		var engineData any
334		if err := json.Unmarshal([]byte(engineJSON), &engineData); err != nil {
335			return nil, fmt.Errorf("failed to parse engine JSON: %w", err)
336		}
337	
338		// Use the existing ExtractEngineConfig function by creating a temporary frontmatter map
339		tempFrontmatter := map[string]any{
340			"engine": engineData,
341		}
342	
343		_, config := c.ExtractEngineConfig(tempFrontmatter)
344		return config, nil
345	}
346	
347	// parseAuthDefinition converts a raw auth config map (from engine.provider.auth) into
348	// an AuthDefinition. It is backward-compatible: a map with only a "secret" key produces
349	// an AuthDefinition with Strategy="" and Secret set (callers normalise Strategy to api-key).
350	func parseAuthDefinition(authObj map[string]any) *AuthDefinition {
351		def := &AuthDefinition{}
352		if s, ok := authObj["strategy"].(string); ok {
353			def.Strategy = AuthStrategy(s)
354		}
355		if s, ok := authObj["secret"].(string); ok {
356			def.Secret = s
357		}
358		if s, ok := authObj["token-url"].(string); ok {
359			def.TokenURL = s
360		}
361		if s, ok := authObj["client-id"].(string); ok {
362			def.ClientIDRef = s
363		}
364		if s, ok := authObj["client-secret"].(string); ok {
365			def.ClientSecretRef = s
366		}
367		if s, ok := authObj["token-field"].(string); ok {
368			def.TokenField = s
369		}
370		if s, ok := authObj["header-name"].(string); ok {
371			def.HeaderName = s
372		}
373		return def
374	}
375	
376	// parseRequestShape converts a raw request config map (from engine.provider.request) into
377	// a RequestShape.
378	func parseRequestShape(requestObj map[string]any) *RequestShape {
379		shape := &RequestShape{}
380		if s, ok := requestObj["path-template"].(string); ok {
381			shape.PathTemplate = s
382		}
383		if q, ok := requestObj["query"].(map[string]any); ok {
384			shape.Query = make(map[string]string, len(q))
385			for k, v := range q {
386				if vs, ok := v.(string); ok {
387					shape.Query[k] = vs
388				}
389			}
390		}
391		if b, ok := requestObj["body-inject"].(map[string]any); ok {
392			shape.BodyInject = make(map[string]string, len(b))
393			for k, v := range b {
394				if vs, ok := v.(string); ok {
395					shape.BodyInject[k] = vs
396				}
397			}
398		}
399		return shape
400	}
