)

func TestExtractEngineConfig(t *testing.T) {
	compiler := NewCompiler()

	tests := []struct {
		name                  string
		frontmatter           map[string]any
		expectedEngineSetting string
		expectedConfig        *EngineConfig
	}{
		{
			name:                  "no engine specified",
