                  "allowed-extensions": {
                    "type": "array",
                    "items": {
                      "type": "string"
                    },
                    "description": "List of allowed file extensions (e.g., [\".json\", \".txt\"]). Default: [\".json\", \".jsonl\", \".txt\", \".md\", \".csv\"]"
                  }
