                "description": "The type of the input value."
              },
              "options": {
                "type": "array",
                "description": "List of allowed values for choice type inputs.",
                "items": {
                  "type": "string"
                }
              },
              "items": {
                "type": "object",
                "description": "Schema for individual array elements. Typically {\"type\": \"string\"}.",
