                  "id": {
                    "type": "string",
                    "description": "Memory identifier (required for array notation, default: 'default')"
                  },
                  "branch-prefix": {
                    "type": "string",
                    "minLength": 4,
                    "maxLength": 32,
                    "pattern": "^[a-zA-Z0-9_-]+$",
                    "description": "Branch prefix for memory storage (default: 'memory'). Must be 4-32 characters, alphanumeric with hyphens/underscores, and cannot be 'copilot'. Applied to all entries in the array. Branch will be named {branch-prefix}/{id}"
                  },
                  "target-repo": {
                    "type": "string",
                    "description": "Target repository for memory storage (default: current repository). Format: owner/repo"
                  },
                  "branch-name": {
                    "type": "string",
                    "description": "Git branch name for memory storage (default: {branch-prefix}/{id} or memory/{id} if branch-prefix not set)"
                  },
                  "file-glob": {
                    "oneOf": [
                      {
                        "type": "string",
                        "description": "Single file glob pattern for allowed files"
                      },
                      {
                        "type": "array",
                        "description": "Array of file glob patterns for allowed files",
                        "items": {
                          "type": "string"
                        }
                      }
                    ],
                    "description": "Glob patterns for files to include in repository memory. Supports wildcards (e.g., '**/*.md', 'docs/**/*.json') to filter cached files."
                  },
                  "max-file-size": {
                    "type": "integer",
                    "minimum": 1,
                    "maximum": 104857600,
                    "description": "Maximum size per file in bytes (default: 10240 = 10KB)"
                  },
                  "max-file-count": {
                    "type": "integer",
                    "minimum": 1,
                    "maximum": 1000,
                    "description": "Maximum file count per commit (default: 100)"
                  },
                  "max-patch-size": {
                    "type": "integer",
                    "minimum": 1,
                    "maximum": 102400,
                    "description": "Maximum total patch size in bytes (default: 10240 = 10KB, max: 102400 = 100KB). The total size of the git diff must not exceed this value."
                  },
                  "description": {
                    "type": "string",
                    "description": "Optional description for this memory that will be shown in the agent prompt"
                  },
                  "create-orphan": {
                    "type": "boolean",
                    "description": "Create orphaned branch if it doesn't exist (default: true)"
                  },
                  "wiki": {
                    "type": "boolean",
                    "description": "Use the GitHub Wiki git repository instead of the regular repository. When enabled, files are stored in and read from the wiki, and the agent will be instructed to follow GitHub Wiki markdown syntax (default: false)"
                  },
                  "allowed-extensions": {
                    "type": "array",
                    "items": {
                      "type": "string"
                    },
                    "description": "List of allowed file extensions (e.g., [\".json\", \".txt\"]). Default: [\".json\", \".jsonl\", \".txt\", \".md\", \".csv\"]"
                  }
                },
                "additionalProperties": false
              },
              "minItems": 1,
              "examples": [
                [
                  {
                    "id": "default",
                    "branch-name": "memory/default"
                  },
                  {
                    "id": "session",
                    "branch-name": "memory/session"
                  }
                ]
              ],
              "maxItems": 10
            }
          ],
          "examples": [
            true,
            null,
            {
              "branch-name": "memory/agent-state"
            },
            [
              {
                "id": "default",
                "branch-name": "memory/default"
              },
              {
                "id": "logs",
                "branch-name": "memory/logs",
                "max-file-size": 524288
              }
            ]
          ]
        }
      },
      "additionalProperties": {
        "oneOf": [
          {
            "type": "string",
            "description": "Simple tool string for basic tool configuration"
