func TestIsExpression(t *testing.T) {
	tests := []struct {
		name string
		s    string
		want bool
	}{
		{
			name: "simple expression",
			s:    "${{ inputs.engine-version }}",
			want: true,
		},
		{
			name: "expression with spaces",
			s:    "${{ github.ref }}",
			want: true,
		},
		{
			name: "complex expression",
			s:    "${{ inputs.engine-version || 'latest' }}",
			want: true,
		},
		{
			name: "literal version string",
			s:    "1.2.3",
			want: false,
		},
		{
