		{
			name: "empty string",
			s:    "",
			want: false,
		},
		{
			name: "partial match only braces",
			s:    "{{ some value }}",
			want: false,
		},
		{
			name: "dollar sign only",
			s:    "$ something",
			want: false,
		},
		{
			name: "env var style",
			s:    "$ENGINE_VERSION",
			want: false,
