func TestGenerateCopilotInstallerSteps_ExpressionVersion(t *testing.T) {
	// Test that expression versions are passed via env var, not inlined in shell command
	expressionVersion := "${{ inputs.engine-version }}"
	stepName := "Install GitHub Copilot CLI"

	steps := GenerateCopilotInstallerSteps(expressionVersion, stepName)

	if len(steps) != 1 {
		t.Errorf("Expected 1 step, got %d", len(steps))
		return
	}

	stepContent := strings.Join(steps[0], "\n")

	// Should use env var for the version
	if !strings.Contains(stepContent, "ENGINE_VERSION: "+expressionVersion) {
		t.Errorf("Expected ENGINE_VERSION env var with expression value, got:\n%s", stepContent)
	}

	// Should reference $ENGINE_VERSION in the run command
	if !strings.Contains(stepContent, "$ENGINE_VERSION") {
		t.Errorf("Expected $ENGINE_VERSION reference in run command, got:\n%s", stepContent)
	}

	// Should NOT inline the expression directly in the run command
	if strings.Contains(stepContent, "install_copilot_cli.sh ${{") {
		t.Errorf("Expression should NOT be inlined directly in run command (injection risk), got:\n%s", stepContent)
	}
}

